// Import necessary modules
import sys
import math

class Solution:
  def __init__(self):
    self.heap = []
  def parent(self, p):
    return (p-1)//2
  def left(self, p):
    return 2*p+1
  def right(self, p):
    return 2*p+2
  def getMin(self):
    return self.heap[0]
  def fixHeap(self, i):
    while i > 0 and self.heap[parent(i)] > self.heap[i]:
      # Heapify up operation to maintain heap property
      self.heap[parent(i)], self.heap[i] = self.heap[i], self.heap[parent(i)]
      i = parent(i)
  def insert(self, x):
    self.heap.append(x)
    self.fixHeap(len(self.heap)-1)
  def printHeap(self):
    for num in self.heap:
      print(num, end=' ')
    print()
  def solve(self):
    # Read input from sys.stdin
    num_of_elements = int(input())
    for _ in range(num_of_elements):
      x = int(input())
      self.insert(x)
      self.printHeap()

  def main(self):
    # Run from sys.stdin
    self.solve()

if __name__ == '__main__':
  s = Solution()
  s.main()

