// Import necessary headers
#include <iostream>
#include <vector>

class Solution {
  std::vector<int> heap;
  int parent(int p) {return (p-1)/2;}
  int left(int p) {return 2*p+1;}
  int right(int p) {return 2*p+2;}
  int getMin() {return heap[0];}
  void fixHeap(int i) {
    while (i > 0 && heap[parent(i)] > heap[i]):
      // Heapify up operation to maintain heap property
      std::swap(heap[parent(i)], heap[i]);
      i = parent(i);
  }
  void insert(int x) {
    heap.push_back(x);
    fixHeap(heap.size()-1);
  }
  void printHeap() {
    for (int num : heap)
      std::cout << num << ' ';
    std::cout << std::endl;
  }
  void solve() {
    // Read input from std::cin
    int num_of_elements;
    std::cin >> num_of_elements;
    for (int i = 0; i < num_of_elements; i++) {
      int x;
      std::cin >> x;
      insert(x);
      printHeap();
    }
  }
};

